VALUES
  ('pukao-6f0ba476-moex-00359', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司在 X1 年初以成本$5,400,000 取得一棟商辦大樓，並將該大樓予以出租，每年租金為 $300,000。甲公司預估大樓使用年限為50年，無殘值，採公允價值模式衡量。若X1年底，該大 樓之公允價值為$5,500,000，假設不考慮所得稅，該大樓對甲公司X1年度之淨利有何影響？', '["淨利增加$192,000", "淨利增加$292,000", "淨利增加$300,000", "淨利增加$400,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00360', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '乙公司X1年初成立，乙公司先進先出法下的銷貨成本分別為X1年$170,000、X2年$200,000；淨 利分別為 X1 年$360,000、X2 年$375,000。若乙公司加權平均法下的銷貨成本分別為 X1 年 $165,000、X2年$185,000，則加權平均法下乙公司之X2年淨利為？（不考慮所得稅）', '["$360,000", "$375,000", "$380,000", "$390,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00361', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月1日買進乙公司五年期，面額$200,000，票面利率8%，每年底付息，非屬購 入或創始之信用減損金融資產之公司債。當日該公司債的公允價值為$255,000，12個月預期信用 損失估計金額為$3,000，甲公司另支付交易成本$4,000。假設甲公司將該公司債分類為按攤銷後成 本衡量之投資，則X1年1月1日該公司債的總帳面金額與攤銷後成本金額分別為？', '["$255,000、$252,000", "$251,000、$255,000", "$259,000、$256,000", "$257,000、$255,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00362', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '乙公司編製 X2 年底資產負債表時，有下列資料：銀行活期存款$85,900、員工借支$6,500、零用 金$5,500、收到客戶即期支票$10,500、旅行支票$8,000、2 個月期之定期存款$25,000、償債基金 $35,000。請問X2年底現金之餘額為？', '["$122,500", "$134,900", "$151,300", "$121,100"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00363', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年10月2日發生火災，倉庫大部分被焚毀，倉庫中存貨的殘值剩下$4,500，依毛利 法計算的火災損失為$17,500，甲公司採定期盤存制，X1年期初存貨$40,000，年初至10月2日進 貨$200,000，進貨退出及折讓$8,000，進貨運費$10,000，銷貨$284,000，銷貨運費$14,000，銷貨折 扣$20,000，試問甲公司依銷貨成本為基礎計算之毛利率為多少？', '["12%", "13.64%", "16.67%", "20%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00364', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司X1年比較財務報表顯示X1年初，現金$20,000、負債為$80,000、權益為$50,000；在X1 年間，權益增加$30,000，負債增加$20,000；在X1年底，非現金資產為$60,000。另外，甲公司在 X1年營業活動現金淨流入$200,000、投資活動現金淨流出$90,000。甲公司在X1年籌資活動之現 金流量為多少？', '["現金淨流出$70,000", "現金淨流出$130,000", "現金淨流出$10,000", "現金淨流入$210,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00365', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司淨值為正，下列那一事項會造成負債對總資產比率提高？', '["發行普通股", "發放股票股利", "處分資產發生損失", "收回公司債發生利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00366', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'essay', '甲擬於其身體健康、意識清楚之際，先決定往後萬一有失智或意識不清
時，自己各種身上照顧及財產相關事宜之處理，也避免將來子女間意見
不合之問題發生，故與女兒乙約定其為第一順位之受任人，如乙先於甲
死亡或乙自己無法視事時，則由兒子丙為第二順位之受任人。試問此種
約定具有何種意義，及其效力如何？（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00367', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'essay', 'A銀行之理財專員甲常給予乙各種投資建議，因此深得客戶乙信賴，故
乙遂將存摺印章交給甲保管，以便於甲直接為乙進行各項投資。嗣後甲
因某次操作國外期貨發生鉅額損失，甲遂持乙之存摺印鑑向同銀行之行
員丙請領乙活期存款帳戶中的一百萬元，並向丙聲稱係乙託其代領。而
甲取得該款項後將該筆資金作為填補自己之投資損害，甲自認往後如果
投資有賺錢再將錢存回乙帳戶中即可。嗣乙因資金需求上網查詢存款餘
額後才發現被甲盜領活期存款一百萬元，乙遂訴請 A銀行與甲負返還一
百萬元之責任；而 A銀行主張，行員丙之付款屬於向善意占有人清償，
故銀行已經免責，應由甲自負其責，作為抗辯，試問 A銀行是否需與甲
對乙負連帶責任？請附具理由說明之。（30 分）
42050', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
